CREATE OR REPLACE PROCEDURE get_employee_detail (
 p_emp_id IN NUMBER,
 p_name OUT VARCHAR2,
 p_salary OUT NUMBER
)
AS
BEGIN
 SELECT first_name || ' ' || last_name, salary
 INTO p_name, p_salary
 FROM employees
 WHERE employee_id = p_emp_id;
END;
/
-- Calling the procedure
DECLARE
 v_name VARCHAR2(100);
 v_salary NUMBER;
BEGIN
 get_employee_detail(101, v_name, v_salary);
 DBMS_OUTPUT.PUT_LINE('Name: ' || v_name || ', Salary: ' || v_salary);
END;

/* C Program with Embedded SQL */
#include <stdio.h>

EXEC SQL BEGIN DECLARE SECTION;
 int emp_id;
 char emp_name[50];
 float salary;
EXEC SQL END DECLARE SECTION;

EXEC SQL INCLUDE SQLCA;

int main() {
 /* Connect to database */
 EXEC SQL CONNECT :username IDENTIFIED BY :password;

 /* Declare cursor */
 EXEC SQL DECLARE emp_cursor CURSOR FOR
 SELECT employee_id, first_name, salary
 FROM employees
 WHERE department_id = 10;

 /* Open and fetch */
 EXEC SQL OPEN emp_cursor;
 while (SQLCODE == 0) {
 EXEC SQL FETCH emp_cursor INTO :emp_id, :emp_name, :salary;
 printf("%d %s %.2f\n", emp_id, emp_name, salary);
 }
 EXEC SQL CLOSE emp_cursor;
 EXEC SQL COMMIT WORK;
 return 0;
}
